const fs = require("fs");
const path = require("path");

function ensureDir(dir) {
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
}

function readMap(file) {
    if (!fs.existsSync(file)) return {};
    try { return JSON.parse(fs.readFileSync(file, "utf8")); } catch (e) { return {}; }
}

/**
 * Setup function for cypress-json-html-reporter to attach to Cypress Node Events.
 * 
 * This enables the reporter to link videos and passed/failed screenshots properly.
 * Attach this inside the `setupNodeEvents` in `cypress.config.js`.
 * 
 * @param {*} on - The Cypress event listener function
 * @param {*} config - The Cypress config object
 */
function setupJsonHtmlReporterEvents(on, config) {
    // Store maps in the root `reports` folder by default
    const REPORTS_DIR = path.join(process.cwd(), "reports");
    const SCREENSHOT_MAP_FILE = path.join(REPORTS_DIR, ".screenshot-map.json");
    const VIDEO_MAP_FILE = path.join(REPORTS_DIR, ".video-map.json");
    const BROWSER_INFO_FILE = path.join(REPORTS_DIR, ".browser-info.json");

    // ── Browser Info ──────────────────────────────────────────────────────
    on("before:browser:launch", (browser = {}, launchOptions) => {
        ensureDir(REPORTS_DIR);
        if (browser.name) {
            fs.writeFileSync(BROWSER_INFO_FILE, JSON.stringify({ browserName: browser.name, browserVersion: browser.version }, null, 2));
        }
        return launchOptions;
    });

    on("before:run", (details) => {
        if (details && details.browser && details.browser.name) {
            ensureDir(REPORTS_DIR);
            fs.writeFileSync(BROWSER_INFO_FILE, JSON.stringify({ browserName: details.browser.name, browserVersion: details.browser.version }, null, 2));
        }
    });

    // ── Screenshot Map ────────────────────────────────────────────────────
    on("after:screenshot", (details) => {
        ensureDir(REPORTS_DIR);
        const map = readMap(SCREENSHOT_MAP_FILE);
        const key = path.basename(details.path, ".png");
        map[key] = details.path;
        fs.writeFileSync(SCREENSHOT_MAP_FILE, JSON.stringify(map, null, 2));
        return details;
    });

    // ── Video Map ─────────────────────────────────────────────────────────
    on("after:spec", (spec, results) => {
        if (!results || !results.video || results.stats.failures === 0) return;
        ensureDir(REPORTS_DIR);
        const map = readMap(VIDEO_MAP_FILE);
        const failedSuites = new Set();
        if (results.tests) {
            results.tests.forEach((test) => {
                if (test.state === "failed" && test.title && test.title.length > 0) {
                    failedSuites.add(test.title[0]);
                }
            });
        }
        failedSuites.forEach((suite) => {
            map[suite] = results.video;
        });
        fs.writeFileSync(VIDEO_MAP_FILE, JSON.stringify(map, null, 2));
    });
}

module.exports = { setupJsonHtmlReporterEvents };
